import React, { useState, useEffect } from 'react';
import './App.css';

function App() {
    const [messages, setMessages] = useState([]);
    const [input, setInput] = useState('');

    useEffect(() => {
        setMessages([{ text: 'HELIX ready. What shall we hack?', sender: 'ai' }]);
